syntax = "proto3";

package ar2pq9Proto;

option go_package = "github.com/IGS-ARCADE-DIVISION-RD2/uk_815_pirates_queen_9999_proto/go/ar2pq9Proto";

// ingame
message Column {
  repeated int32 Col = 1; // 單列盤面symbol資料
}

// AwardData 中獎紀錄
message AwardData {
  int32 Symbol = 1;   // 中獎symbol
  int32 Count = 2;    // 中獎顆數
  double Odds = 3;    // 賠率
  int32 Multiple = 4; // 倍率(max(1,累加中獎位置倍率>=2的倍率))
  double Win = 5;     // 贏分=倍率*賠率

  repeated int32 EliminatePos = 6; // 消去位置
}

// TargetData 標靶紀錄
message TargetData {
  int32 Symbol = 1; // 標靶symbol
  int32 Pos = 2;    // 標靶pos

  repeated int32 EliminatePos = 3; // 消去位置
}

// BountyData 懸賞令紀錄
message BountyData {
  int32 BaseSymbol = 1;    // 原始symbol(比對用)
  int32 BountySymbol = 2;  // 懸賞令symbol(轉換用)
  int32 MultipleIndex = 3; // 懸賞令倍率index
  int32 Multiple = 4;      // 懸賞令倍率
}

// ScatterData scatter紀錄
message ScatterData {
  int32 Symbol = 1;    // scatter symbol
  int32 Pos = 2;       // scatter pos
  int32 ExtraSpin = 3; // 額外spin數
}

message IntAry {
  repeated int32 Data = 1;
}

message doubleAry {
	repeated double data = 1;
}

// 盤面 資訊
message PlateInfo {
  repeated Column PlateSymbol = 1;      // 盤面
  repeated Column PlateSymbolLog = 2;   // 盤面(表演後log)
  repeated AwardData AwardDataVec = 3;  // 中獎紀錄
  double Win = 4;                       // 贏分
  repeated IntAry FeaturePosQueue = 5;  // 特殊symbol位置
  repeated int32 EliminatePos = 6;      // 消去位置
  repeated TargetData TargetDataVec = 7;   // 標靶紀錄
  repeated BountyData BountyDataVec = 8;   // 懸賞令紀錄
  repeated ScatterData ScatterDataVec = 9; // scatter紀錄
  repeated IntAry BasePlateIndex = 10;      // 底板index(展平)
}


// RoundInfo 盤面回應
message RoundInfo {
  int32 AwardTypeFlag = 1; // 得獎類型旗標
  double RoundWin = 2;     // 本round total贏分

  int32 CurrFeverGameType = 3;
  int32 NextFeverGameType = 4;
  int32 FeverRemainRound = 5;    // Fevergame剩餘局數
  int32 FeverNowRound = 6;       // Fevergame現在局數
  int32 FeverTotalRound = 7;     // Fevergame總局數
  int32 FreePickNum = 8;         // 免費pick數
  repeated int32 FreePickItem = 9; // 免費pick項目(0:target, 1:bounty, 2:scatter)

  repeated IntAry PreBasePlateIndex = 10; // 上一手底板index(展平)

  int32 MGReelWeightResult = 11;
  bool MaxFlag = 12; // 是否已達到最大倍率

  repeated PlateInfo PlateQueue = 13; // 盤面資料
}

// SpinAck 盤面總資料
message SpinAck {
  repeated RoundInfo RoundQueue = 1; // 回合資料
  double FreeTotalWin = 2;           // free game 總贏分(client free game贏分結算時用)
  double TotalWin = 3;               // 總贏分(main game + free game)
  double Bet = 4;                    // 下注額
}

message StateInfo {
}

//
message GameInfoData {
  bool ShowExtra = 1;
  repeated double Mul = 2;

  double MaxBet = 6;
  repeated double BuyMul = 7;
}

message BuyReq {
  double BaseBet = 1;
  int32 BuyType = 2;
}

