1	import { error, log } from "cc";
2	import { BaseState, eventManager, msgBoxManager, newBottombarManager, SlotBottomBarState } from "db://astarte-framework/Managers";
3	import GameView from "../GameView";
4	import Game_Define, { FeaturePosQueueType } from "../Game_Define";
5	import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
6	// import protocol from "../Test/ar2pq9Proto.js";
7	import { REEL_UI_MANAGER_EVENT } from "../Reel/ReelManager";
8	import { AudioManager } from "../Audio/AudioManager";
9	import { Define } from "db://astarte-framework/utilis";
10	import { tools } from "db://astarte-framework/utilis";
11	
12	export class AwardState extends BaseState
13	{
14	    private m_gameView: GameView = null;
15	    private m_processTick: number = 0;
16	    
17	    /**
18	     * @ch 現在盤面資訊
19	     */
20	    private m_currentPlateInfo: protocol.ar2pq9Proto.IPlateInfo = null;
21	
22	    constructor( gameView: GameView )
23	    {
24	        super();
25	        this.m_gameView = gameView;
26	    }
27	
28	    public OnEnter()
29	    {
30	
31	        log( "OnEnter State : AWARD" );
32	        this.m_processTick = 0;
33	        
34	
35	        const spinAck = this.m_gameView.SpinAck;
36	        const winValue = spinAck.RoundQueue[ this.m_gameView.CurRoundIndex ].RoundWin;
37	        const totalWin = spinAck.TotalWin;
38	
39	        
40	
41	        /**@ch 設定盤面符號不暗 */
42	        this.m_gameView.SlotReels.SetSymbolDark( false, -1 );
43	
44	        if ( winValue > 0 && !this.m_gameView.IsGoingToFree )
45	        {
46	            this.ProcessFinalAward( winValue,totalWin, false );
47	        }
48	    }
49	
50	    public OnProcess( dt: number )
51	    {
52	        if ( this.m_processTick > 0 )
53	        {
54	            this.m_processTick -= dt;
55	            if ( this.m_processTick > 0 ) return;
56	        }
57	        if ( this.m_gameView.BigWin.IsEnd )
58	        {
59	            this.m_gameView.BigWin.node.active = false;
60	            this.m_gameView.FadeBgmIn();
61	            this.m_gameView.AfterShowWin();
62	        }
63	    }
64	
65	    public OnLeave()
66	    {
67	        this.m_currentPlateInfo = null;
68	        this.m_gameView.CanStopBigWin = false;
69	    }
70	
71	    
72	
73	    /**
74	     * @ch 處理最後報獎
75	     * @param totalWin 總贏分
76	     * @param isNotShowNormalWin 是否不顯示NormalWin
77	     */
78	    private ProcessFinalAward(winValue: number, totalWin: number, isNotShowNormalWin: boolean) : void {
79	
80	        const bet: number = Game_Define.GetNowBetValue();
81	        const rate = winValue / bet;
82	
83	        if ( winValue <= 0 ) return;
84	
85	        // 小獎（倍率 < BigWin 門檻）
86	        if ( rate < Game_Define.BigWinWinRule.BIG_WIN_MIN )
87	        {
88	            if ( isNotShowNormalWin ) return;
89	
90	            // 小獎音效
91	            if (rate < 3) {
92	                AudioManager.Play(AudioManager.AudioClips.Small_Win01);
93	            } else if (rate < 5) {
94	                AudioManager.Play(AudioManager.AudioClips.Small_Win02);
95	            } else {
96	                AudioManager.Play(AudioManager.AudioClips.Small_Win03);
97	            }
98	            this.m_gameView.ShowSmallWinLabel( winValue, Game_Define.SMALLWIN_TIME );
99	            this.m_processTick = Game_Define.SMALLWIN_TIME;
100	            
101	        }
102	        // 大獎
103	        else
104	        {
105	            this.m_gameView.SetManualVisible( false );
106	            let lvl = 0;
107	            // SUPER >= 50x, MEGA >= 25x, BIG >= 10x
108	            if ( rate >= Game_Define.BigWinWinRule.SUPER_WIN_MIN )
109	            {
110	                lvl = 3; // SUPER
111	            }
112	            else if ( rate >= Game_Define.BigWinWinRule.MEGA_WIN_MIN )
113	            {
114	                lvl = 2; // MEGA
115	            }
116	            else
117	            {
118	                lvl = 1; // BIG
119	            }
120	
121	            this.m_gameView.ShowBigWin( winValue, lvl );
122	            this.m_gameView.FadeBgmOut();
123	            newBottombarManager.SetSpinState( SlotBottomBarState.GET_AWARD_NO_AUTO );
124	
125	            // 0.5s 延遲保護：防止玩家太快跳過看不到動畫
126	            this.m_gameView.CanStopBigWin = false;
127	            Define.Wait( this.m_gameView, 0.5 ).then( () =>
128	            {
129	                this.m_gameView.CanStopBigWin = true;
130	                if ( newBottombarManager.IsAutoSpin )
131	                {
132	                    newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP );
133	                }
134	                else
135	                {
136	                    newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
137	                }
138	            } );
139	        }
140	        newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: this.m_gameView.RoundWin } );
141	    }
142	
143	    
144	
145	    /**@ch 取得Scatter中獎位置
146	     * @returns Scatter中獎位置
147	     */
148	    private GetScatterPositions(): number[] {
149	        let scatterPositions: number[] = [];
150	       
151	        if (this.m_currentPlateInfo.FeaturePosQueue.length > 0) {
152	            const featurePosQueue = this.m_currentPlateInfo.FeaturePosQueue[FeaturePosQueueType.Scatter];
153	            for (let position of featurePosQueue.Data) {
154	                scatterPositions.push(position);
155	            }
156	        }
157	        return scatterPositions;
158	    }
159	
160	    
161	
162	    /**
163	     * @ch 設定Reel黑幕顯示
164	     * @param isShow 是否顯示
165	     */
166	    private SetReelBlackMaskShow(isShow: boolean) {
167	        eventManager.Dispatch(isShow ? REEL_UI_MANAGER_EVENT.SHOW_BLACK_MASK : REEL_UI_MANAGER_EVENT.HIDE_BLACK_MASK);
168	    }
169	
170	    /**
171	     * @ch 暫停背景音樂
172	     */
173	    private PauseBgm() {
174	        // 暫停背景音樂
175	        if (this.m_gameView.IsFreeGame) {
176	            this.m_gameView.PauseFreeGameBgm();
177	        }
178	        else {
179	            this.m_gameView.PauseMainGameBgm();
180	        }
181	    }
182	
183	    /**
184	     * @ch 恢復背景音樂
185	     */
186	    private ResumeBgm() {
187	        // 恢復背景音樂
188	        if (this.m_gameView.IsFreeGame) {
189	            this.m_gameView.ResumeFreeGameBgm();
190	        }
191	        else {
192	            this.m_gameView.ResumeMainGameBgm();
193	        }
194	    }
195	
196	    
197	    
198	    /**
199	     * @ch 表演變換Wild Symbol效果
200	     * @param featureWildData 變換Wild Symbol資料
201	     */
202	    
203	
204	    /**
205	     * @ch 表演Bingo Combo音效
206	     * @param comboCount Combo數量
207	     */
208	    private PlayBingoComboSound(comboCount: number) {
209	        // 假如小於最小值則不播放
210	        if (comboCount < Game_Define.BINGO_COMBO_MIN_COUNT) {
211	            return;
212	        }
213	
214	        // 假如大於最大值則播放最大值
215	        if (comboCount > Game_Define.BINGO_COMBO_MAX_COUNT) {
216	            comboCount = Game_Define.BINGO_COMBO_MAX_COUNT;
217	        }
218	
219	        AudioManager.Play(AudioManager.AudioClips[`Bingo_Combo0${comboCount}`]);
220	    }
221	
222	    /**
223	     * @ch 表演MaxFlag MessageBox
224	     */
225	    private async PlayMaxFlagMessageBox() : Promise<void> {
226	        log("PlayMaxFlagMessageBox");
227	        return new Promise<void>((resolve) => {
228	            msgBoxManager.ShowMessageBox(
229	                Define.StringKey.MSGBOX_MAX_REWARD,
230	                Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO,
231	                () => {
232	                    resolve();
233	                }
234	            );
235	        });
236	    }
237	}

