285	
286	        try {
287	            // 產生時間戳記檔名
288	            const now = new Date();
289	            const timestamp = now.getFullYear().toString() +
290	                (now.getMonth() + 1).toString().padStart(2, '0') +
291	                now.getDate().toString().padStart(2, '0') + '_' +
292	                now.getHours().toString().padStart(2, '0') +
293	                now.getMinutes().toString().padStart(2, '0') +
294	                now.getSeconds().toString().padStart(2, '0');
295	            const filename = `spin_data_${timestamp}.bin`;
296	
297	            // 將 Uint8Array 轉換為 Blob
298	            const dataArray = new Uint8Array(this.m_lastSpinData);
299	            const blob = new Blob([dataArray], { type: 'application/octet-stream' });
