import { _decorator, Component, sys, log, error, Input, input, EventKeyboard, KeyCode, profiler } from "cc";
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
import { eventManager } from "db://astarte-framework/Managers";
import { BS_SPINE_CTRL_EVENT } from "./BSSpineCtrl";
import { BS_SPINE_TYPE } from "./BSSpineCtrl";
import { RT_EVENT } from "./RTCtrl";
import { stateManager } from "db://astarte-framework/Managers";
import Game_Define from "./Game_Define";
const { ccclass, property } = _decorator;

/**
 * @ch 除錯工具事件定義
 */
export const DEBUG_TOOL_EVENT = {
    /**@ch GameView 接收到 Spin 資料 - 參數: (data: Uint8Array) */
    SPIN_DATA_RECEIVED: "DEBUG_TOOL_EVENT_SPIN_DATA_RECEIVED",

    /**@ch GameView 請求取得待用的 Spin 資料 - 參數: (func(spinAck: protocol.ar2rhProto.ISpinAck) => void) */
    GET_PENDING_SPIN_DATA: "DEBUG_TOOL_EVENT_GET_PENDING_SPIN_DATA",

    /**@ch GameView 通知已使用待用資料，請求清除 */
    CLEAR_PENDING_SPIN_DATA: "DEBUG_TOOL_EVENT_CLEAR_PENDING_SPIN_DATA"
}

/**
 * @ch 除錯工具管理器
 * @description 提供 Spin 資料的下載、上傳、重放等除錯功能
 * @note 此工具僅在開發環境下啟用，正式版本會被編譯器移除
 */
@ccclass('DebugToolManager')
export class DebugToolManager extends Component {

    /**@ch 啟用除錯功能（只在開發環境生效）*/
    private m_enableDebugTools: boolean = true;

    /**@ch 最後一次 spin 的原始資料 */
    private m_lastSpinData: Uint8Array = null;

    /**@ch 待用的除錯 Spin 資料（用於下次 Spin 時替換 Server 資料）*/
    private m_pendingSpinData: protocol.ar2pq9Proto.ISpinAck = null;

    /**@ch 按鍵狀態追蹤 */
    private m_isCtrlPressed: boolean = false;
    private m_isAltPressed: boolean = false;
    private m_isShowProfiler: boolean = false;

    //#region 生命週期

    onLoad() {
        // 只在開發環境且非原生平台時啟用
        if (!this.IsDebugEnvironment()) {
            this.enabled = false;
            return;
        }

        // 初始化 Profiler 顯示狀態（避免一開始狀態不同步）
        this.m_isShowProfiler = this.GetProfilerIsShowing();

        this.RegisterKeyboardEvents();
        this.RegisterEventListeners();
        // this.ExposeToWindow();

        log("🛠️ DebugToolManager 已啟用");
    }

    onDestroy() {
        if (this.IsDebugEnvironment()) {
            this.UnregisterKeyboardEvents();
            this.UnregisterEventListeners();
            this.RemoveFromWindow();
        }
    }

    //#endregion 生命週期

    //#region 環境檢測

    /**
     * @ch 檢查是否為除錯環境
     * @returns 是否為除錯環境
     */
    private IsDebugEnvironment(): boolean {
        // 只在 Web 環境啟用
        const isWebEnvironment = !sys.isNative && typeof window !== 'undefined';

        return isWebEnvironment && this.m_enableDebugTools;
    }

    //#endregion 環境檢測

    //#region 視窗暴露

    /**
     * @ch 暴露到全域 window 物件（使用命名空間避免衝突）
     */
    private ExposeToWindow(): void {
        if (typeof window !== 'undefined') {
            // 使用專案特定的命名空間
            (window as any)['__PIRATES_QUEEN_DEBUG__'] = this;
            log("💡 DebugToolManager 已暴露到全域，可使用: window.__PIRATES_QUEEN_DEBUG__");
            log("   - 下載資料: window.__PIRATES_QUEEN_DEBUG__.DownloadLastSpinData()");
            log("   - 上傳資料: window.__PIRATES_QUEEN_DEBUG__.UploadAndLoadSpinData()");
            log("   - 快捷鍵: Ctrl+Alt+D 下載資料 | Ctrl+Alt+U 上傳資料 | Ctrl+Alt+P 切換 Profiler");
        }
    }

    /**
     * @ch 從 window 移除暴露
     */
    private RemoveFromWindow(): void {
        if (typeof window !== 'undefined') {
            delete (window as any)['__PIRATES_QUEEN_DEBUG__'];
        }
    }

    //#endregion 視窗暴露

    //#region 鍵盤事件

    /**
     * @ch 註冊鍵盤事件
     */
    private RegisterKeyboardEvents(): void {
        input.on(Input.EventType.KEY_DOWN, this.OnKeyDown, this);
        input.on(Input.EventType.KEY_UP, this.OnKeyUp, this);
    }

    /**
     * @ch 取消註冊鍵盤事件
     */
    private UnregisterKeyboardEvents(): void {
        input.off(Input.EventType.KEY_DOWN, this.OnKeyDown, this);
        input.off(Input.EventType.KEY_UP, this.OnKeyUp, this);
    }

    /**
     * @ch 按鍵按下事件
     */
    private OnKeyDown(event: EventKeyboard): void {
        // 追蹤 Ctrl 鍵
        if (event.keyCode === KeyCode.CTRL_LEFT || event.keyCode === KeyCode.CTRL_RIGHT) {
            this.m_isCtrlPressed = true;
        }
        // 追蹤 Alt 鍵
        if (event.keyCode === KeyCode.ALT_LEFT || event.keyCode === KeyCode.ALT_RIGHT) {
            this.m_isAltPressed = true;
        }

        // Ctrl+Alt+D: 下載最後一次 spin 資料
        if (event.keyCode === KeyCode.KEY_D && this.m_isCtrlPressed && this.m_isAltPressed) {
            this.DownloadLastSpinData();
        }

        // Ctrl+Alt+U: 上傳並載入 spin 資料
        if (event.keyCode === KeyCode.KEY_U && this.m_isCtrlPressed && this.m_isAltPressed) {
            this.UploadAndLoadSpinData();
        }

        // Ctrl+Alt+P: 顯示/隱藏性能分析器
        if (event.keyCode === KeyCode.KEY_P && this.m_isCtrlPressed && this.m_isAltPressed) {
            this.ShowProfiler();
        }

        // if (event.keyCode === KeyCode.KEY_T ) {
        //     eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, 'Aim', false,()=>{log('Aim 動畫播放完成')});
        //     eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON, 'S_Aim', false,()=>{log('Aim 動畫播放完成')});

        // }

        if (event.keyCode === KeyCode.KEY_R ) {
             eventManager.Dispatch(RT_EVENT.AWARD_IN_RT);
         }

         if (event.keyCode === KeyCode.KEY_F ) {
             eventManager.Dispatch(RT_EVENT.AWARD_OUT_RT);
         }

        // if (event.keyCode === KeyCode.KEY_U ) {
        //     stateManager.NextState(Game_Define.GameState.ENTER_FREE);

        // }

        // if (event.keyCode === KeyCode.KEY_L ) {
        //     stateManager.NextState(Game_Define.GameState.LEAVE_FREE);
        // }
    }

    /**
     * @ch 按鍵釋放事件
     */
    private OnKeyUp(event: EventKeyboard): void {
        // 釋放 Ctrl 鍵
        if (event.keyCode === KeyCode.CTRL_LEFT || event.keyCode === KeyCode.CTRL_RIGHT) {
            this.m_isCtrlPressed = false;
        }
        // 釋放 Alt 鍵
        if (event.keyCode === KeyCode.ALT_LEFT || event.keyCode === KeyCode.ALT_RIGHT) {
            this.m_isAltPressed = false;
        }
    }

    //#endregion 鍵盤事件

    //#region 事件監聽
    /**
     * @ch 註冊事件監聽器
     */
    private RegisterEventListeners(): void {
        eventManager.Register(DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED, this);
        eventManager.Register(DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA, this);
        eventManager.Register(DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA, this);
    }

    /**
     * @ch 取消註冊事件監聽器
     */
    private UnregisterEventListeners(): void {
        eventManager.UnRegister(DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED, this);
        eventManager.UnRegister(DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA, this);
        eventManager.UnRegister(DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA, this);
    }

    /**
     * @ch 事件處理
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent(event: string, ...args: any[]): void {
        if ( !this.IsDebugEnvironment() )
        {
            return;
        }

        switch (event) {
            case DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED:
                // 參數: (data: Uint8Array)
                if (args.length > 0 ) {
                    this.SaveSpinData(args[0]);
                } else {
                    error("❌ SPIN_DATA_RECEIVED 事件接收到無效的資料格式");
                }
                break;

            case DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA:
                if (typeof args[0] === "function") {
                    args[0](this.m_pendingSpinData);
                }
                break;

            case DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA:
                this.m_pendingSpinData = null;
                break;
        }
    }
    //#endregion 事件監聽

    //#region 公開 API

    /**
     * @ch 儲存 Spin 資料 (私有方法，透過事件觸發)
     * @param data Spin 原始資料
     */
    private SaveSpinData(data: Uint8Array): void {
        if (!this.IsDebugEnvironment()) {
            return;
        }
        this.m_lastSpinData = data;
        log(`💾 已儲存 Spin 資料: ${data.length} bytes`);
    }

    /**
     * @ch 下載最後一次 spin 的原始資料為 .bin 檔案
     * @description 可在瀏覽器控制台手動調用：window.__PIRATES_QUEEN_DEBUG__.DownloadLastSpinData()
     */
    public DownloadLastSpinData(): void {
        if (!this.IsDebugEnvironment()) {
            log("⚠️ 除錯工具已停用");
            return;
        }

        if (!this.m_lastSpinData) {
            log("⚠️ 尚無 spin 資料可供下載");
            return;
        }

        try {
            // 產生時間戳記檔名
            const now = new Date();
            const timestamp = now.getFullYear().toString() +
                (now.getMonth() + 1).toString().padStart(2, '0') +
                now.getDate().toString().padStart(2, '0') + '_' +
                now.getHours().toString().padStart(2, '0') +
                now.getMinutes().toString().padStart(2, '0') +
                now.getSeconds().toString().padStart(2, '0');
            const filename = `spin_data_${timestamp}.bin`;

            // 將 Uint8Array 轉換為 Blob
            const dataArray = new Uint8Array(this.m_lastSpinData);
            const blob = new Blob([dataArray], { type: 'application/octet-stream' });

            // 建立下載連結
            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = filename;

            // 觸發下載
            document.body.appendChild(link);
            link.click();

            // 清理
            document.body.removeChild(link);
            URL.revokeObjectURL(url);

            log(`✅ Spin 資料已下載: ${filename} (${this.m_lastSpinData.length} bytes)`);
        } catch (err) {
            error(`❌ 下載失敗: ${err}`);
        }
    }

    /**
     * @ch 上傳並載入 .bin 檔案（用於重放 spin 資料）
     * @description 可在瀏覽器控制台手動調用：window.__PIRATES_QUEEN_DEBUG__.UploadAndLoadSpinData()
     */
    public UploadAndLoadSpinData(): void {
        if (!this.IsDebugEnvironment()) {
            log("⚠️ 除錯工具已停用");
            return;
        }

        try {
            // 建立隱藏的 file input
            const input = document.createElement('input');
            input.type = 'file';
            input.accept = '.bin';
            input.style.display = 'none';

            input.onchange = (e: any) => {
                const file = (e.target as HTMLInputElement).files?.[0];
                if (!file) {
                    log("⚠️ 未選擇檔案");
                    return;
                }

                log(`📁 讀取檔案: ${file.name} (${file.size} bytes)`);

                const reader = new FileReader();
                reader.onload = (event: ProgressEvent<FileReader>) => {
                    try {
                        const arrayBuffer = event.target?.result as ArrayBuffer;
                        if (!arrayBuffer) {
                            error("❌ 讀取檔案失敗：無法取得資料");
                            return;
                        }

                        // 轉換為 Uint8Array
                        const uint8Array = new Uint8Array(arrayBuffer);
                        log(`📦 成功讀取 ${uint8Array.length} bytes 資料`);

                        // 解析 SpinAck 資料
                        this.ParseAndApplySpinData(uint8Array);

                    } catch (parseError) {
                        error(`❌ 解析檔案失敗: ${parseError}`);
                    }
                };

                reader.onerror = () => {
                    error(`❌ 讀取檔案失敗: ${reader.error}`);
                };

                reader.readAsArrayBuffer(file);
            };

            // 觸發檔案選擇
            document.body.appendChild(input);
            input.click();
            document.body.removeChild(input);

        } catch (err) {
            error(`❌ 上傳失敗: ${err}`);
        }
    }

    /**
     * @ch 啟用/停用除錯工具
     * @param enable 是否啟用
     */
    public SetEnableDebugTools(enable: boolean): void {
        this.m_enableDebugTools = enable;
        log(`${enable ? '✅ 已啟用' : '❌ 已停用'} 除錯工具功能`);
    }

    /**
     * @ch 取得待用的 Spin 資料
     * @returns 待用的 SpinAck 資料，若無則回傳 null
     */
    public GetPendingSpinData(): protocol.ar2pq9Proto.ISpinAck | null {
        return this.m_pendingSpinData;
    }

    /**
     * @ch 清除待用的 Spin 資料
     */
    public ClearPendingSpinData(): void {
        if (this.m_pendingSpinData) {
            log("🗑️ 已清除待用的除錯 Spin 資料");
            this.m_pendingSpinData = null;
        }
    }

    //#endregion 公開 API

    //#region 私有方法

    /**
     * @ch 解析並暫存 spin 資料（等待下次 Spin 時使用）
     * @param data Uint8Array 格式的 spin 資料
     */
    private ParseAndApplySpinData(data: Uint8Array): void {
        try {
            // 解碼為 SpinAck
            const spinAck: protocol.ar2pq9Proto.ISpinAck = protocol.ar2pq9Proto.SpinAck.decode(data);
            log("✅ SpinAck 解碼成功", spinAck);

            // 儲存為待用資料（將在下次玩家點擊 Spin 時替換 Server 資料）
            this.m_pendingSpinData = spinAck;
            log("💾 除錯 Spin 資料已暫存，將在下次 Spin 時使用");

        } catch (decodeError) {
            error(`❌ 解碼 SpinAck 失敗: ${decodeError}`);
        }
    }

    /**
     * @ch 取得 Profiler 目前是否已顯示（Web 環境）
     * @description
     * - 優先使用引擎 API（若存在）
     * - 否則以 DOM（#cc-stats）做保守判斷
     */
    private GetProfilerIsShowing(): boolean {
        // 引擎某些版本可能提供此方法，但 typings 不一定會帶出來
        const profilerAny = profiler as any;
        if (typeof profilerAny?.isShowingStats === 'function') {
            return !!profilerAny.isShowingStats();
        }

        if (typeof document === 'undefined') {
            return false;
        }

        const statsEl = document.getElementById('cc-stats');
        if (!statsEl) {
            return false;
        }

        // 避免元素存在但被隱藏（例如 display:none）
        if (typeof window !== 'undefined' && typeof window.getComputedStyle === 'function') {
            const style = window.getComputedStyle(statsEl);
            return style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0';
        }

        return true;
    }

    /**
     * @ch 顯示/隱藏性能分析器
     */
    private ShowProfiler(): void {
        const nextIsShow = !this.m_isShowProfiler;
        if (nextIsShow) {
            profiler.showStats();
        }
        else {
            profiler.hideStats();
        }

        // 執行後再同步一次，避免因引擎/設定因素導致實際狀態不一致
        this.m_isShowProfiler = this.GetProfilerIsShowing();
    }
    //#endregion 私有方法
}

