                newBottombarManager.SetAutoPlaySettingPanelFreeGameString( Define.StringKey.AUTO_PLAY_PANEL_ENTER_FREEGAME );

                newExtraManager.SetCanAutoShowRankboardUI();

                // Extra Bet 按鈕在伺服器資料就緒後才顯示
                this.ShowExtraBet();

                //音效
                this.LoadSound();
                break;
            }

        case Define.AckType.lastSpin:
        case Define.AckType.spin:
            {

                // 透過事件發送原始 spin data 給 DebugToolManager
                eventManager.Dispatch(DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED, data);

                let info: protocol.ar2pq9Proto.ISpinAck = protocol.ar2pq9Proto.SpinAck.decode(data);

                // 🔧 透過 DEBUG_TOOL_EVENT 事件取得待用的除錯重放資料
                eventManager.Dispatch(DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA, (pendingData: protocol.ar2pq9Proto.ISpinAck) => {
                    if (pendingData) {
                        log("🎮 使用除錯重放資料替換 Server 資料");
                        info = pendingData;
                        eventManager.Dispatch(DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA);
                    }
                });

                this.OnRecvSpinAck(info);
                break;
            }

        case Define.AckType.unshow: {

            let info: protocol.ar2pq9Proto.ISpinAck = protocol.ar2pq9Proto.SpinAck.decode( data );
            this.m_unshowSpinAck = info;
            break;
        }
    }
